import sys

class Solution:
    def minFallingPathSum(self, grid: list[list[int]]) -> int:
        n = len(grid)
        dp = [[0]*n for _ in range(n)]
        dp[0] = grid[0]
        for i in range(1, n):
            for j in range(n):
                dp[i][j] = grid[i][j] + min(dp[i-1][max(0, j-1):min(n, j+2)])
        return min(dp[-1])

