#include <numeric>
#include <bits/stdc++.h>
using namespace std;

class Solution {
public:
    int minFallingPathSum(vector<vector<int>>& grid) {
        int n = grid.size();
        vector<vector<int>> dp(n, vector<int>(n));
        dp[0] = grid[0];
        for (int i = 1; i < n; i++) {
            for (int j = 0; j < n; j++) {
                int min_val = INT_MAX;
                for (int k = max(0, j-1); k <= min(n-1, j+1); k++) {
                    min_val = min(min_val, dp[i-1][k]);
                }
                dp[i][j] = grid[i][j] + min_val;
            }
        }
        int ans = INT_MAX;
        for (int j = 0; j < n; j++) {
            ans = min(ans, dp[n-1][j]);
        }
        return ans;
    }
};

int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);
    int n;
    if (!(cin >> n)) return 0;
    vector<vector<int>> grid(n, vector<int>(n));
    for (int i = 0; i < n; i++) {
        for (int j = 0; j < n; j++) {
            if (!(cin >> grid[i][j])) return 0;
        }
    }
    Solution sol;
    int ans = sol.minFallingPathSum(grid);
    cout << ans << '\n';
    return 0;
}
